import React, { useState, useEffect } from 'react';
import Course from './Course.jsx';
import InstructorDashboard from './InstructorDashboard.jsx';
import dataService from './services/api.js';
import LoadingSpinner from './components/LoadingSpinner.jsx';
import ErrorBoundary from './components/ErrorBoundary.jsx';
import { ToastProvider, useToast } from './components/Toast.jsx';
import { removeDuplicateCourses } from './utils/courseUtils';
import { validateCourse } from './utils/validation.js';
import useCourseStore from './store/courseStore.js';
import { Bell, Settings, User, ChevronDown, Moon, Sun } from 'lucide-react';

const AppContent = () => {
  const [currentPage, setCurrentPage] = useState('courses');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const { showToast } = useToast();

  // Use Zustand store
  const {
    courses,
    notifications,
    user,
    loading,
    error,
    setCourses,
    addCourse,
    updateCourse,
    deleteCourse,
    setLoading,
    setError,
    getStats,
    markNotificationRead
  } = useCourseStore();

  const defaultCourses = [
    {id:1,title:'Full Stack Web Development',desc:'Master HTML, CSS, JS, React, Node.js and build dynamic web apps.',level:'Intermediate',rating:'4.8',time:'8h 30m',cat:'development',instructor:'John Parker',img:'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=400&h=200&fit=crop',price:99,enrolled:1250,progress:65},
    {id:2,title:'Machine Learning Basics',desc:'Understand algorithms, train models, and deploy ML apps with Python.',level:'Advanced',rating:'4.9',time:'10h',cat:'ai',instructor:'Dr. Aisha Khan',img:'https://images.unsplash.com/photo-1581090700227-1e37b190418e?w=400&h=200&fit=crop',price:149,enrolled:890,progress:0},
    {id:3,title:'UI/UX Design for Beginners',desc:'Learn Figma, typography, wireframing, and design psychology.',level:'Beginner',rating:'4.6',time:'6h 45m',cat:'design',instructor:'Elena Rose',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=400&h=200&fit=crop',price:79,enrolled:2100,progress:100},
    {id:4,title:'Entrepreneurship Essentials',desc:'Learn how to start and scale your business with proven models.',level:'Intermediate',rating:'4.7',time:'5h 20m',cat:'business',instructor:'Michael Stone',img:'https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=400&h=200&fit=crop',price:89,enrolled:567,progress:30},
    {id:5,title:'Data Science with Python',desc:'Dive into data visualization, cleaning, and statistical analysis.',level:'Advanced',rating:'4.9',time:'12h 15m',cat:'ai',instructor:'Dr. Lin Wei',img:'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=400&h=200&fit=crop',price:159,enrolled:1890,progress:0},
    {id:6,title:'Digital Marketing Strategy',desc:'Master SEO, SEM, and social media advertising for maximum reach.',level:'Beginner',rating:'4.5',time:'7h 0m',cat:'business',instructor:'Sarah Lee',img:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=400&h=200&fit=crop',price:69,enrolled:3200,progress:85}
  ];

  const [isDarkMode, setIsDarkMode] = useState(false);
  const stats = getStats();

  useEffect(() => {
    loadCourses();
    const darkMode = localStorage.getItem('darkMode') === 'true';
    setIsDarkMode(darkMode);
    if (darkMode) document.documentElement.classList.add('dark');
  }, []);

  const toggleDarkMode = () => {
    const newDarkMode = !isDarkMode;
    setIsDarkMode(newDarkMode);
    localStorage.setItem('darkMode', newDarkMode.toString());
    document.documentElement.classList.toggle('dark', newDarkMode);
  };

  const loadCourses = async () => {
    try {
      setLoading(true);
      const response = await dataService.getCourses();
      const uniqueCourses = removeDuplicateCourses(response.data || defaultCourses);
      setCourses(uniqueCourses);
      setError(null);
      if (uniqueCourses.length > 0) {
        showToast(`Loaded ${uniqueCourses.length} courses successfully!`, 'success');
      }
    } catch (err) {
      // Fallback to default courses if API fails
      setCourses(defaultCourses);
      setError('Using offline data - some features may be limited');
      showToast('Using offline data', 'warning');
      console.error('Error loading courses:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddCourse = async (newCourse) => {
    const validation = validateCourse(newCourse);
    if (!validation.isValid) {
      showToast(`Validation failed: ${validation.errors[0]}`, 'error');
      throw new Error(validation.errors.join(', '));
    }

    try {
      const response = await dataService.createCourse(newCourse);
      const courseData = response.data || { ...newCourse, id: Date.now(), enrolled: 0, rating: '5.0' };
      addCourse(courseData);
      showToast('Course created successfully!', 'success');
      return courseData;
    } catch (err) {
      // Fallback to local storage if API fails
      const courseData = { ...newCourse, id: Date.now(), enrolled: 0, rating: '5.0' };
      addCourse(courseData);
      showToast('Course created locally - will sync when online', 'warning');
      console.error('Error adding course:', err);
      return courseData;
    }
  };

  const handleUpdateCourse = async (courseId, updatedCourse) => {
    try {
      const response = await dataService.updateCourse(courseId, updatedCourse);
      updateCourse(courseId, response.data || updatedCourse);
      showToast('Course updated successfully!', 'success');
      return response.data || updatedCourse;
    } catch (err) {
      // Fallback to local update if API fails
      updateCourse(courseId, updatedCourse);
      showToast('Course updated locally - will sync when online', 'warning');
      console.error('Error updating course:', err);
      return updatedCourse;
    }
  };

  const handleDeleteCourse = async (courseId) => {
    try {
      await dataService.deleteCourse(courseId);
      deleteCourse(courseId);
      showToast('Course deleted successfully!', 'success');
    } catch (err) {
      // Fallback to local deletion if API fails
      deleteCourse(courseId);
      showToast('Course deleted locally - will sync when online', 'warning');
      console.error('Error deleting course:', err);
    }
  };

  const handleNotificationClick = (notification) => {
    markNotificationRead(notification.id);
    setShowNotifications(false);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow-lg border-b fixed w-full z-50 backdrop-blur-md bg-white/95">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-8">
              <div className="flex items-center space-x-2">
                <div className="w-8 h-8 bg-gradient-to-r from-blue-600 to-purple-600 rounded-lg flex items-center justify-center">
                  <span className="text-white font-bold text-sm">R</span>
                </div>
                <span className="font-bold text-xl bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
                  RiseGen
                </span>
              </div>
              <div className="flex space-x-1">
                <button 
                  onClick={() => setCurrentPage('courses')}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
                    currentPage === 'courses' 
                      ? 'bg-blue-100 text-blue-700 shadow-sm' 
                      : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50'
                  }`}
                >
                  Courses ({stats.totalCourses})
                </button>
                <button 
                  onClick={() => setCurrentPage('instructor')}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${
                    currentPage === 'instructor' 
                      ? 'bg-blue-100 text-blue-700 shadow-sm' 
                      : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50'
                  }`}
                >
                  Instructor Dashboard
                </button>
              </div>
            </div>

            <div className="flex items-center space-x-4">
              {/* Dark Mode Toggle */}
              <button
                onClick={toggleDarkMode}
                className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                title={isDarkMode ? 'Switch to Light Mode' : 'Switch to Dark Mode'}
              >
                {isDarkMode ? (
                  <Sun className="w-5 h-5" />
                ) : (
                  <Moon className="w-5 h-5" />
                )}
              </button>

              {/* Notifications */}
              <div className="relative">
                <button
                  onClick={() => setShowNotifications(!showNotifications)}
                  className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors relative"
                >
                  <Bell className="w-5 h-5" />
                  {stats.unreadNotifications > 0 && (
                    <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center animate-pulse">
                      {stats.unreadNotifications > 9 ? '9+' : stats.unreadNotifications}
                    </span>
                  )}
                </button>

                {showNotifications && (
                  <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-100">
                      <h3 className="font-semibold text-gray-900">Notifications</h3>
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {notifications.map(notification => (
                        <button
                          key={notification.id} 
                          onClick={() => handleNotificationClick(notification)}
                          className={`w-full text-left px-4 py-3 hover:bg-gray-50 border-l-4 transition-colors ${
                            notification.unread ? 'border-blue-500 bg-blue-50/30' : 'border-transparent'
                          }`}
                        >
                          <p className="text-sm text-gray-900">{notification.message}</p>
                          <p className="text-xs text-gray-500 mt-1">{notification.time}</p>
                          {notification.unread && (
                            <span className="inline-block w-2 h-2 bg-blue-500 rounded-full mt-1"></span>
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              {/* User Menu */}
              <div className="relative">
                <button
                  onClick={() => setShowUserMenu(!showUserMenu)}
                  className="flex items-center space-x-2 p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                >
                  <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center">
                    {user.avatar ? (
                      <img src={user.avatar} alt={user.name} className="w-full h-full rounded-full object-cover" />
                    ) : (
                      <User className="w-4 h-4 text-white" />
                    )}
                  </div>
                  <span className="text-sm font-medium hidden sm:block">{user.name}</span>
                  <ChevronDown className="w-4 h-4" />
                </button>

                {showUserMenu && (
                  <div className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <a href="#" className="flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-50">
                      <User className="w-4 h-4 mr-3" />
                      Profile
                    </a>
                    <a href="#" className="flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-50">
                      <Settings className="w-4 h-4 mr-3" />
                      Settings
                    </a>
                    <hr className="my-2" />
                    <a href="#" className="flex items-center px-4 py-2 text-sm text-red-600 hover:bg-red-50">
                      Logout
                    </a>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </nav>

      <div className="pt-16">
        {loading && (
          <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-blue-50 to-purple-50">
            <LoadingSpinner size="large" text="Loading your courses..." />
          </div>
        )}
        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mx-4 mt-4">
            <strong className="font-bold">Error: </strong>
            <span className="block sm:inline">{error}</span>
            <button 
              onClick={loadCourses}
              className="ml-4 bg-red-600 text-white px-3 py-1 rounded text-sm hover:bg-red-700"
            >
              Retry
            </button>
          </div>
        )}
        {!loading && !error && (
          <>
            {currentPage === 'courses' && <Course courses={courses} />}
            {currentPage === 'instructor' && (
              <InstructorDashboard 
                courses={courses} 
                onAddCourse={handleAddCourse} 
                onUpdateCourse={handleUpdateCourse}
                onDeleteCourse={handleDeleteCourse}
                onRefresh={loadCourses}
              />
            )}
          </>
        )}
      </div>
    </div>
  );
};

// Main App component with providers
const App = () => {
  return (
    <ErrorBoundary>
      <ToastProvider>
        <AppContent />
      </ToastProvider>
    </ErrorBoundary>
  );
};

export default App;
